import json
from kafka import KafkaConsumer
from kafka.errors import NoBrokersAvailable
from typing import Dict, Any

class TransactionHandler:
    def __init__(self):
        self.kafka_config = {
            'bootstrap_servers': ['localhost:9092'],
            'auto_offset_reset': 'latest'
        }
        
    def deserialize(self, message: bytes) -> Dict[str, Any]:
        return json.loads(message.decode('utf-8'))
    
    def execute_handler(self, event_type: str, data: Dict[str, Any]) -> None:
        if event_type == 'transaction':
            # Execute business logic for transaction events
            print("Transaction Event Processed:", data)
        elif event_type == 'refund':
            # Execute business logic for refund events
            print("Refund Event Processed:", data)
    
    def start_consumption(self, topics: str):
        try:
            consumer = KafkaConsumer(
                group_id='transaction_group',
                **self.kafka_config
            )
            
            consumer.subscribe([topics])
            
            while True:
                message = consumer.poll(timeout_ms=1000)
                for topic in message:
                    print(f"Consumed from {topic.topic}")
                    for event in message[topic]:
                        data: Dict[str, Any] = self.deserialize(event.value)
                        event_type: str = type(data).__name__
                        self.execute_handler(event_type, data)
        except NoBrokersAvailable as e:
            print("Error starting consumer:", e)


if __name__ == "__main__":
    handler = TransactionHandler()
    handler.start_consumption('financial_transactions')